#include <bits/stdc++.h>
using namespace std;

const int N=14;

int t,n,m,val[N],g[N][N];
long long f[1<<13][N][N],h[1<<13][N][N];

int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n;i++){
            scanf("%d",&val[i]);
            for(int j=1;j<=n;j++)
                g[i][j]=0;
        }
        for(int i=1;i<=m;i++){
            int u,v;
            scanf("%d%d",&u,&v);
            g[u][v]=g[v][u]=1;
        }
        if(n==1){
            printf("%d 1\n",val[1]);
            continue;
        }
        memset(f,0,sizeof(f));
        memset(h,0,sizeof(h));
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++)
                if(g[i][j]){
                    f[(1<<i-1)+(1<<j-1)][i][j]=val[i]+val[j]+val[i]*val[j];
                    h[(1<<i-1)+(1<<j-1)][i][j]=1;
                }
        for(int i=1;i<1<<n;i++)
            for(int j=1;j<=n;j++)
                if(i&(1<<j-1))
                    for(int k=1;k<=n;k++){
                        if(!f[i][j][k])
                            continue;
                        for(int w=1;w<=n;w++)
                            if(!(i&(1<<w-1)) && g[k][w]){
                                long long num=f[i][j][k]+val[w]+val[k]*val[w];
                                if(g[j][w])
                                    num+=val[j]*val[k]*val[w];
                                if(f[i|(1<<w-1)][k][w]<num){
                                    f[i|(1<<w-1)][k][w]=num;
                                    h[i|(1<<w-1)][k][w]=0;
                                }
                                if(f[i|(1<<w-1)][k][w]==num)
                                    h[i|(1<<w-1)][k][w]+=h[i][j][k];
                            }
                    }
        long long ans=0,sum=0;
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++){
                if(ans<f[(1<<n)-1][i][j])
                    ans=f[(1<<n)-1][i][j],sum=0;
                if(ans==f[(1<<n)-1][i][j])
                    sum+=h[(1<<n)-1][i][j];
            }
        printf("%lld %lld\n",ans,sum/2);
    }
    return 0;
}
